  "files": {
    "includes": [
      "apps/**/src/**/*.ts",
      "apps/**/src/**/*.tsx",
      "packages/**/src/**/*.ts",
      "packages/**/src/**/*.tsx",
      "*.json",
      ".claude/**/*.ts"
    ]
  }
}

