     1→import path from 'node:path';
     2→import type { CheckMessage } from '@belt/core';
     3→import ts from 'typescript';
     4→import type { TypecheckOptions, TypecheckResult } from './types.js';
     5→
     6→interface RunOptions extends TypecheckOptions {
     7→  cwd: string;
     8→}
     9→
    10→export async function runTypecheck(options: RunOptions): Promise<TypecheckResult> {
    11→  const startTime = performance.now();
    12→  const {
    13→    cwd,
    14→    include = ['src'],
    15→    exclude = ['node_modules'],
    16→    tsconfig = 'tsconfig.json',
    17→    onlyErrors = true,
    18→    files,
    19→  } = options;
    20→
    21→  const includePaths = files?.length
    22→    ? files.map((f) => path.resolve(cwd, f))
    23→    : include.map((dir) => path.join(cwd, dir));
    24→
    25→  const configPath = ts.findConfigFile(cwd, ts.sys.fileExists, tsconfig);
    26→
    27→  if (!configPath) {
    28→    return {
    29→      success: false,
    30→      errorCount: 1,
    31→      warningCount: 0,
    32→      messages: [{ severity: 'error', message: `Could not find ${tsconfig} in ${cwd}` }],
    33→      filesChecked: 0,
    34→      duration: performance.now() - startTime,
    35→    };
    36→  }
    37→
    38→  const configFile = ts.readConfigFile(configPath, ts.sys.readFile);
    39→  const { options: compilerOptions, fileNames } = ts.parseJsonConfigFileContent(
    40→    configFile.config,
    41→    ts.sys,
    42→    path.dirname(configPath),
    43→    { noEmit: true },
    44→  );
    45→
    46→  const filesToCheck = files?.length ? includePaths : fileNames;
    47→
    48→  const program = ts.createProgram({
    49→    rootNames: filesToCheck,
    50→    options: compilerOptions,
    51→  });
    52→
    53→  const allDiagnostics = ts.getPreEmitDiagnostics(program);
    54→  const messages: CheckMessage[] = [];
    55→
    56→  for (const diagnostic of allDiagnostics) {
    57→    if (onlyErrors && diagnostic.category !== ts.DiagnosticCategory.Error) {
    58→      continue;
    59→    }
    60→
    61→    const location = getDiagnosticLocation(diagnostic, cwd);
    62→
    63→    if (location.filePath) {
    64→      const isIncluded = includePaths.some((p) => location.filePath?.startsWith(p));
    65→      const isExcluded = exclude.some((pattern) => location.filePath?.includes(pattern));
    66→
    67→      if (!isIncluded || isExcluded) continue;
    68→    }
    69→
    70→    const message = ts.flattenDiagnosticMessageText(diagnostic.messageText, '\n');
    71→
    72→    messages.push({
    73→      severity: diagnostic.category === ts.DiagnosticCategory.Error ? 'error' : 'warning',
