import type { BeltPlugin, CheckResult } from '@belt/core';
import { runTypecheck } from './typecheck.js';
import type { TypecheckOptions } from './types.js';

export function typecheckPlugin(options: TypecheckOptions = {}): BeltPlugin {
  return {
    name: 'typecheck',
    version: '0.1.0',

    apply(belt) {
      belt.registerCommand({
        id: 'typecheck',
        name: 'Type Check',
        description: 'Run TypeScript type checking on local source files',
        category: 'Quality',
        async handler(ctx) {
          ctx.log.info('Running type check...');

          const result = await runTypecheck({ cwd: ctx.cwd, ...options });

          if (result.success) {
            ctx.log.info(
              `Type check passed (${result.filesChecked} files in ${result.duration}ms)`,
            );
          } else {
            ctx.log.error(`Type check failed: ${result.errorCount} errors`);
            for (const msg of result.messages) {
              const loc = msg.file ? `${msg.file}:${msg.line}:${msg.column}` : '';
              ctx.log.error(`  ${loc}: ${msg.message}`);
            }
          }
        },
      });

      belt.hooks.checkResults.tapPromise('typecheck', async (results, ctx) => {
        const result = await runTypecheck({ cwd: ctx.cwd, ...options });

        const checkResult: CheckResult = {
          success: result.success,
          errorCount: result.errorCount,
          warningCount: result.warningCount,
          messages: result.messages,
          duration: result.duration,
        };

        return [...results, checkResult];
      });
    },
  };
}

