): Obj {
  const sortedSetters = Object.entries(setters).sort(([a], [b]) => {
    return a.split('.').length > b.split('.').length ? 1 : -1;
  });

  sortedSetters.forEach(([k, v]) => {
    // @ts-expect-error
    setProperty(object, k, v);
  });

  return object as never;
}

export type WithFalsyValues<Obj> = { [K in keyof Obj]?: Obj[K] | Falsy };

/**
 * @internal
 * @param record
 */
export function assertValues<Obj>(record: WithFalsyValues<Obj>): asserts record is Obj {
  let errMessage = '';

  if (!isObject(record)) {
    throw new InvariantError('Expected plain object', assertValues);
  }

  Object.keys(record).forEach((key) => {
    try {
      getProperty(record, key as never);
    } catch (e: any) {
      const prefix = errMessage ? ' ' : '';
      errMessage += prefix + e.message;
    }
  });

  if (errMessage) {
    throw new InvariantError(errMessage, assertValues);
  }
}

/**
 * Asserts object against 'Falsy' property values
 * @param record
 */
export function requireAll<Obj>(record: WithFalsyValues<Obj>): Obj {
  return moveStackTrace(() => {
    assertValues(record);
    return record;
  }, requireAll);
}
